import itertools

def pairings(lst):
    if not lst:
        yield []
    else:
        first=lst[0]
        for i in range(1,len(lst)):
            second=lst[i]
            for rest in pairings(lst[1:i]+lst[i+1:]):
                yield [(first,second)]+rest

def interleave(p,q,n=6):
    a,b=sorted(p); c,d=sorted(q)
    # on line/circle order; for four distinct endpoints interleave if exactly one of c,d in (a,b)
    return ((a<c<b) != (a<d<b))  # one inside interval

counts={}
ps=[]
for P in pairings(list(range(1,7))):
    P=tuple(tuple(sorted(x)) for x in P)
    # sort pairs lex
    P=tuple(sorted(P))
    k=0
    edges=[]
    for i in range(3):
        for j in range(i+1,3):
            if interleave(P[i],P[j]):
                k+=1; edges.append((P[i],P[j]))
    counts[k]=counts.get(k,0)+1
    ps.append((k,P,edges))
counts, ps

